      out.write("\n");
      out.write("<script>\n");
      out.write("/* ââââââââââââââââââââââââââââââââââââââââââââââââââââââ\n");
      out.write("   Dynamic Autocomplete â calls /search?q=<input>&mode=suggest\n");
      out.write("   and renders a dropdown list beneath the search bar.\n");
      out.write("ââââââââââââââââââââââââââââââââââââââââââââââââââââââ */\n");
      out.write("(function () {\n");
      out.write("    const input   = document.getElementById('exploreSearchInput');\n");
      out.write("    const suggest = document.getElementById('exploreSearchSuggest');\n");
      out.write("    const form    = document.getElementById('exploreSearchForm');\n");
      out.write("    if (!input || !suggest) return;\n");
      out.write("\n");
      out.write("    let debounceTimer;\n");
      out.write("    let activeIdx = -1;\n");
      out.write("\n");
      out.write("    input.addEventListener('input', function () {\n");
      out.write("        clearTimeout(debounceTimer);\n");
      out.write("        const q = this.value.trim();\n");
      out.write("        if (q.length < 2) { hideSuggest(); return; }\n");
      out.write("        debounceTimer = setTimeout(() => fetchSuggestions(q), 220);\n");
      out.write("    });\n");
      out.write("\n");
      out.write("    function fetchSuggestions(q) {\n");
      out.write("        const url = form.action + '?q=' + encodeURIComponent(q) + '&mode=suggest';\n");
      out.write("        fetch(url)\n");
      out.write("            .then(r => r.json())\n");
      out.write("            .then(renderSuggestions)\n");
      out.write("            .catch(() => hideSuggest());\n");
      out.write("    }\n");
      out.write("\n");
      out.write("    function renderSuggestions(items) {\n");
      out.write("        suggest.innerHTML = '';\n");
      out.write("        activeIdx = -1;\n");
      out.write("        if (!items || items.length === 0) { hideSuggest(); return; }\n");
      out.write("\n");
      out.write("        items.forEach((text, i) => {\n");
      out.write("            const li = document.createElement('li');\n");
      out.write("            li.textContent = text;\n");
      out.write("            li.style.cssText = 'padding:10px 18px; cursor:pointer; font-family:Poppins,sans-serif; font-size:0.9rem; color:var(--text-main); transition:background 0.15s;';\n");
      out.write("            li.addEventListener('mouseenter', () => setActive(i));\n");
      out.write("            li.addEventListener('click', () => { input.value = text; hideSuggest(); form.submit(); });\n");
      out.write("            suggest.appendChild(li);\n");
      out.write("        });\n");
      out.write("        suggest.style.display = 'block';\n");
      out.write("    }\n");
      out.write("\n");
      out.write("    function setActive(i) {\n");
      out.write("        const items = suggest.querySelectorAll('li');\n");
      out.write("        items.forEach((el, j) => {\n");
      out.write("            el.style.background = j === i ? 'var(--color-border)' : '';\n");
      out.write("        });\n");
      out.write("        activeIdx = i;\n");
      out.write("    }\n");
      out.write("\n");
      out.write("    // Keyboard navigation\n");
      out.write("    input.addEventListener('keydown', function (e) {\n");
      out.write("        const items = suggest.querySelectorAll('li');\n");
      out.write("        if (!items.length) return;\n");
      out.write("        if (e.key === 'ArrowDown')  { e.preventDefault(); setActive(Math.min(activeIdx + 1, items.length - 1)); }\n");
      out.write("        if (e.key === 'ArrowUp')    { e.preventDefault(); setActive(Math.max(activeIdx - 1, 0)); }\n");
